// Parse la réponse d'OpenAI pour détecter le JSON de commande
const aiResponse = $input.first().json.message?.content || $input.first().json.text || '';

let action = 'reply';
let orderData = null;
let message = aiResponse;

// Chercher un bloc JSON dans la réponse
const jsonPatterns = [
  /```json\s*\n?([\s\S]*?)\n?```/,
  /```\s*\n?([\s\S]*?)\n?```/,
  /(\{[\s\S]*"action"\s*:\s*"create_order"[\s\S]*\})/
];

for (const pattern of jsonPatterns) {
  const match = aiResponse.match(pattern);
  if (match) {
    try {
      const parsed = JSON.parse(match[1] || match[0]);
      if (parsed.action === 'create_order' && parsed.data) {
        action = 'create_order';
        orderData = parsed.data;

        // Validation du numéro de téléphone
        if (orderData.client_phone && !orderData.client_phone.startsWith('+596')) {
          orderData.client_phone = '+596' + orderData.client_phone.replace(/[\s\-\.]/g, '').replace(/^0/, '');
        }

        // Nettoyage du téléphone
        orderData.client_phone = orderData.client_phone.replace(/[\s\-\.]/g, '');

        // S'assurer que le format heure est correct (HH:MM)
        if (orderData.heure_souhaitee && !orderData.heure_souhaitee.includes(':')) {
          orderData.heure_souhaitee = orderData.heure_souhaitee.replace(/h/i, ':') + ':00';
        }

        // Recalculer le total pour sécurité
        let calculatedTotal = 0;
        if (Array.isArray(orderData.items)) {
          orderData.items.forEach(item => {
            calculatedTotal += (item.price || 0) * (item.quantity || 1);
          });
        }
        if (orderData.type_service === 'delivery') {
          calculatedTotal += 3; // Frais de livraison
        }
        orderData.total = calculatedTotal;

        // Ajouter les notes
        orderData.notes = orderData.notes || 'Commande via CieloBot';
        orderData.status = 'pending_validation';

        // Message de confirmation pour le client
        message = '🎉 Votre commande a été envoyée avec succès ! Guylian va la valider rapidement. Vous recevrez un lien de paiement sur WhatsApp. Merci et à très vite chez Pizza dal Cielo ! 🍕';
        break;
      }
    } catch (e) {
      // JSON invalide, on continue
    }
  }
}

// Si la réponse entière est un JSON valide
if (action === 'reply') {
  try {
    const parsed = JSON.parse(aiResponse.trim());
    if (parsed.action === 'create_order' && parsed.data) {
      action = 'create_order';
      orderData = parsed.data;

      if (orderData.client_phone && !orderData.client_phone.startsWith('+596')) {
        orderData.client_phone = '+596' + orderData.client_phone.replace(/[\s\-\.]/g, '').replace(/^0/, '');
      }
      orderData.client_phone = orderData.client_phone.replace(/[\s\-\.]/g, '');

      let calculatedTotal = 0;
      if (Array.isArray(orderData.items)) {
        orderData.items.forEach(item => {
          calculatedTotal += (item.price || 0) * (item.quantity || 1);
        });
      }
      if (orderData.type_service === 'delivery') {
        calculatedTotal += 3;
      }
      orderData.total = calculatedTotal;
      orderData.notes = orderData.notes || 'Commande via CieloBot';
      orderData.status = 'pending_validation';

      message = '🎉 Votre commande a été envoyée avec succès ! Guylian va la valider rapidement. Vous recevrez un lien de paiement sur WhatsApp. Merci et à très vite chez Pizza dal Cielo ! 🍕';
    }
  } catch (e) {
    // Pas un JSON, c'est une réponse texte normale
  }
}

return {
  json: {
    action,
    message,
    orderData
  }
};

const orderResponse = $input.first().json;
const previousData = $('Parse Response').first().json;

if (orderResponse.order && orderResponse.order.token) {
  return {
    json: {
      action: 'create_order',
      message: previousData.message,
      token: orderResponse.order.token,
      orderId: orderResponse.order.id,
      success: true
    }
  };
} else {
  return {
    json: {
      action: 'reply',
      message: '😔 Oups, il y a eu un petit souci avec votre commande. Pas de panique ! Vous pouvez nous appeler directement au +596 696 88 72 70 ou passer commande sur le site. Désolé pour la gêne !',
      success: false
    }
  };
}

const data = $input.first().json;

return {
  json: {
    action: 'reply',
    message: data.message
  }
};

// Error handler : si le HTTP Request échoue
return {
  json: {
    action: 'reply',
    message: '😔 Un problème technique est survenu. Vous pouvez commander directement sur notre site pizzadalcielo.vercel.app ou nous appeler au +596 696 88 72 70. Toutes nos excuses !',
    success: false
  }
};
